// JSON Schema Draft 2020-12 adapter — §11.1
// All schemas inlined; no $ref or $defs (CISM nodes are path-scoped, not shape-deduplicated — §11.1)

export function toJsonSchema(cism) {
  const sha256 = (cism && cism.sha256) || 'unknown';
  const inputFormat = (cism && cism.inputFormat) || 'json-object';
  const root = (cism && cism.root) || null;

  const isArrayRoot = inputFormat === 'csv' || inputFormat === 'json-array';
  const rootBody = isArrayRoot
    ? { type: 'array', items: convertNode(root) }
    : convertNode(root);

  return {
    $schema: 'https://json-schema.org/draft/2020-12/schema',
    $id: `urn:bibss:inferred:${sha256}`,
    title: 'Inferred Schema',
    $comment: 'Generated by BIBSS v1.3',
    ...rootBody,
  };
}

function convertNode(node) {
  if (!node) return { type: 'null' };
  switch (node.kind) {
    case 'object':    return convertObject(node);
    case 'array':     return convertArray(node);
    case 'primitive': return convertPrimitive(node);
    case 'union':     return convertUnion(node);
    default:          return { type: 'null' };
  }
}

function convertObject(node) {
  const properties = {};
  const required = [];
  for (const [key, prop] of Object.entries(node.properties || {})) {
    properties[key] = convertNode(prop.targetNode);
    if (prop.required) required.push(key);
  }
  const schema = { type: 'object', properties };
  if (required.length > 0) schema.required = required;
  return schema;
}

function convertArray(node) {
  const schema = { type: 'array' };
  if (node.itemType) schema.items = convertNode(node.itemType);
  return schema;
}

function convertPrimitive(node) {
  const t = node.primitiveType;
  if (node.nullable && t !== 'null') return { type: [t, 'null'] };
  return { type: t };
}

function convertUnion(node) {
  const members = (node.members || []).map(convertNode);
  if (node.nullable) members.push({ type: 'null' });
  return { oneOf: members };
}
